const customInspect = Symbol.for("nodejs.util.inspect.custom");

function formatDetails(details: unknown, indent = "  "): string {
	if (details === undefined || details === null) return "";
	try {
		const json = JSON.stringify(details, null, 2);
		return json.split("\n").join(`\n${indent}`);
	} catch {
		return String(details);
	}
}

export class ConduitError extends Error {
	override name = "ConduitError";
	requestId?: string;
	code?: string;

	constructor(
		message: string,
		opts?: { requestId?: string; code?: string; cause?: unknown },
	) {
		super(message);
		this.requestId = opts?.requestId;
		this.code = opts?.code ?? "conduit_error";
		this.cause = opts?.cause;
	}

	override toString(): string {
		const lines = [`${this.name}: ${this.message}`];
		if (this.code) lines.push(`  Code: ${this.code}`);
		if (this.requestId) lines.push(`  Request ID: ${this.requestId}`);
		return lines.join("\n");
	}

	[customInspect](): string {
		return this.toString();
	}
}

export class InitializationError extends ConduitError {
	override name = "InitializationError";
}

export class UnsupportedRuntimeError extends ConduitError {
	override name = "UnsupportedRuntimeError";
}

export class WebhookVerificationError extends ConduitError {
	override name = "WebhookVerificationError";
}

export class SourceError extends ConduitError {
	override name = "SourceError";
	url?: string;
	status?: number;

	constructor(
		message: string,
		opts?: {
			requestId?: string;
			code?: string;
			cause?: unknown;
			url?: string;
			status?: number;
		},
	) {
		super(message, opts);
		this.url = opts?.url;
		this.status = opts?.status;
	}
}

export class InvalidSourceError extends SourceError {
	override name = "InvalidSourceError";
}

export class RemoteFetchError extends SourceError {
	override name = "RemoteFetchError";
}

export class RemoteFetchTimeoutError extends RemoteFetchError {
	override name = "RemoteFetchTimeoutError";
}

export class RemoteFetchTooLargeError extends RemoteFetchError {
	override name = "RemoteFetchTooLargeError";
}

export class ApiError extends ConduitError {
	override name = "ApiError";
	status: number;
	details?: unknown;

	constructor(
		message: string,
		opts: {
			status: number;
			requestId?: string;
			code?: string;
			details?: unknown;
		},
	) {
		super(message, { code: opts.code, requestId: opts.requestId });
		this.status = opts.status;
		this.details = opts.details;
	}

	override toString(): string {
		const lines = [`${this.name}: ${this.message}`, `  Status: ${this.status}`];
		if (this.code) lines.push(`  Code: ${this.code}`);
		if (this.requestId) lines.push(`  Request ID: ${this.requestId}`);
		if (this.details !== undefined && this.details !== null) {
			lines.push(`  Details: ${formatDetails(this.details)}`);
		}
		return lines.join("\n");
	}
}

export class RateLimitError extends ApiError {
	override name = "RateLimitError";
	retryAfterMs?: number;
}

export class AuthError extends ApiError {
	override name = "AuthError";
}

export class ValidationError extends ApiError {
	override name = "ValidationError";
}

export class InsufficientCreditsError extends ApiError {
	override name = "InsufficientCreditsError";
	required: number;
	available: number;

	constructor(
		message: string,
		opts: {
			status: number;
			requestId?: string;
			code?: string;
			details?: { required?: number; available?: number };
		},
	) {
		super(message, opts);
		this.required = opts.details?.required ?? 0;
		this.available = opts.details?.available ?? 0;
	}
}

